<style>
	/* bare :is() (no element prefix) — 100 chars exactly, stays inline (boundary) */
	:is(.aaaaaa,.bbbbbb,.cccccc,.dddddd,.eeeeee,.ffffff,.gggggg,.hhhhhh,.iiiiiiiiiiiiiiiiii){color:red;}
	/* bare :is() — 101 chars, wraps one-per-line (exceeds print_width) */
	:is(.aaaaaa,.bbbbbb,.cccccc,.dddddd,.eeeeee,.ffffff,.gggggg,.hhhhhh,.iiiiiiiiiiiiiiiiiii){color:blue;}
</style>
